<?php
namespace App\Http\Controllers\Admin;use App\Http\Controllers\Controller;use App\Models\Provider;use Illuminate\Http\Request;use Illuminate\Support\Str;class ProviderController extends Controller{public function index(){$providers=Provider::latest()->paginate(15);return view('admin.providers.index',compact('providers'));}public function create(){return view('admin.providers.form',['provider'=>new Provider]);}public function store(Request $r){$d=$this->data($r);$d['slug']=$d['slug']?:Str::slug($d['name']);Provider::create($d);return redirect()->route('admin.providers.index')->with('success','Provider saved.');}public function edit(Provider $provider){return view('admin.providers.form',compact('provider'));}public function update(Request $r,Provider $provider){$provider->update($this->data($r));return redirect()->route('admin.providers.index')->with('success','Provider updated.');}private function data(Request $r){$d=$r->validate(['name'=>'required|max:191','slug'=>'nullable|max:191','driver'=>'required|max:50','base_url'=>'nullable|max:191','auth_type'=>'required|max:50','api_key'=>'nullable|max:191','api_secret'=>'nullable|max:191','webhook_secret'=>'nullable|max:191','submit_endpoint'=>'nullable|max:191','status_endpoint'=>'nullable|max:191','timeout_seconds'=>'required|integer|min:1','retry_count'=>'required|integer|min:0','status'=>'required|in:active,inactive','config'=>'nullable']);$d['config']=$d['config']?json_decode($d['config'],true):null;return $d;}}
